body.script:
//
          // === SETUP ===
          const canvas = document.getElementById('game');
          const ctx = canvas.getContext('2d');
          let W, H;
          function resize() {
            W = canvas.width = window.innerWidth;
            H = canvas.height = window.innerHeight;
          }
          resize();
          window.addEventListener('resize', resize);

          const ARENA = { w: 2400, h: 2000 };
          const PLAYER_R = 8;
          const BULLET_R = 3;
          const BULLET_SPEED = 9.5;
          const PLAYER_SPEED = 2.6;
          const FIRE_COOLDOWN = 200;
          const BOT_SPEED = 1.5;

          // 0 = Hostile, 1 = Green, 2 = Blue, 3 = Purple, 4 = Orange
          const TEAM_COLORS = ['#1a1a1a', '#39ff14', '#00bfff', '#a020f0', '#ff8c00'];
          const TEAM_ALLY_COLORS = ['#2a2a2a', '#4fcc2c', '#00aaaa', '#7000a0', '#cc5500'];

          // === MAZE & STATE ===
          let walls = [];
          let cellCenters = [];
          let players = [];
          let bullets = [];
          let particles = [];
          let powerups = [];
          let humanPlayers = [null, null, null, null]; // P1, P2, P3, P4
          let keys = {};
          let mouse = { x: 0, y: 0, worldX: 0, worldY: 0 };
          let camera = { x: ARENA.w/2, y: ARENA.h/2, scale: 1.0 };
          let gameOver = false;
          let running = false;
          let shake = 0;
          let powerStarTimer = 1000;
          let powerAllyTimer = 1000;
          let powerShieldTimer = 30000;
          let level = 1;
          let bonusTimer = 30000;
          let bonusActiveTimer = 0;

          const rand = (a, b) => Math.random() * (b - a) + a;
          const dist = (a, b) => Math.hypot(a.x - b.x, a.y - b.y);

          // === AUDIO ENGINE ===
          let audioCtx = null;
          function initAudio() {
            if (!audioCtx) {
              try { audioCtx = new (window.AudioContext || window.webkitAudioContext)(); } catch(e) {}
            }
          }
          function playTone(freq, duration, type, vol, slideTo) {
            if (!audioCtx) return;
            const osc = audioCtx.createOscillator();
            const gain = audioCtx.createGain();
            osc.type = type || 'sine';
            osc.frequency.setValueAtTime(freq, audioCtx.currentTime);
            if (slideTo) osc.frequency.exponentialRampToValueAtTime(slideTo, audioCtx.currentTime + duration);
            gain.gain.setValueAtTime(vol || 0.1, audioCtx.currentTime);
            gain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + duration);
            osc.connect(gain); gain.connect(audioCtx.destination);
            osc.start(); osc.stop(audioCtx.currentTime + duration);
          }
          function playNoise(duration, vol, filterFreq) {
            if (!audioCtx) return;
            const bufferSize = audioCtx.sampleRate * duration;
            const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
            const data = buffer.getChannelData(0);
            for (let i = 0; i < bufferSize; i++) data[i] = Math.random() * 2 - 1;
            const noise = audioCtx.createBufferSource();
            noise.buffer = buffer;
            const filter = audioCtx.createBiquadFilter();
            filter.type = 'lowpass';
            filter.frequency.setValueAtTime(filterFreq || 1000, audioCtx.currentTime);
            filter.frequency.exponentialRampToValueAtTime(100, audioCtx.currentTime + duration);
            const gain = audioCtx.createGain();
            gain.gain.setValueAtTime(vol || 0.1, audioCtx.currentTime);
            gain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + duration);
            noise.connect(filter); filter.connect(gain); gain.connect(audioCtx.destination);
            noise.start(); noise.stop(audioCtx.currentTime + duration);
          }
          const sfx = {
            shoot: () => playTone(900, 0.08, 'square', 0.04, 400),
            hexShoot: () => { playTone(200, 0.15, 'sawtooth', 0.08, 80); playNoise(0.1, 0.05, 800); },
            empty: () => playTone(150, 0.05, 'sine', 0.03),
            collectStar: () => { playTone(800, 0.08, 'square', 0.08, 1200); setTimeout(() => playTone(1200, 0.06, 'square', 0.06), 60); },
            collectAlly: () => { [400, 600, 800].forEach((f, i) => setTimeout(() => playTone(f, 0.1, 'sine', 0.1), i * 60)); },
            collectShield: () => { [600, 800, 1000].forEach((f, i) => setTimeout(() => playTone(f, 0.2, 'sine', 0.12), i * 80)); },
            bounce: () => playTone(300, 0.04, 'sine', 0.03),
            wallBreak: () => { playNoise(0.2, 0.15, 1500); playTone(100, 0.1, 'sawtooth', 0.1, 50); },
            hit: () => playTone(120, 0.08, 'square', 0.08, 60),
            explode: () => { playNoise(0.4, 0.2, 800); playTone(80, 0.3, 'sawtooth', 0.1, 30); },
            bonus: () => { playTone(200, 0.5, 'sine', 0.1, 1200); playTone(300, 0.5, 'sawtooth', 0.05, 1500); },
            levelUp: () => { [523, 659, 784, 1046].forEach((f, i) => setTimeout(() => playTone(f, 0.2, 'sine', 0.1), i * 120)); },
            gameOver: () => { [400, 300, 200, 100].forEach((f, i) => setTimeout(() => playTone(f, 0.3, 'sawtooth', 0.1), i * 150)); }
          };

          // === MAZE GENERATION ===
          const HEX_R = 100;
          const HEX_W = Math.sqrt(3) * HEX_R;
          const HEX_H = 2 * HEX_R;

          function generateMaze() {
            walls = [];
            cellCenters = [];
            const cells = new Map();
            const grid = [];

            for (let q = -10; q <= 10; q++) {
              for (let r = -10; r <= 10; r++) {
                const x = HEX_W * (q + r / 2);
                const y = HEX_H * 3 / 4 * r;
                if (x > -ARENA.w / 2 - HEX_R && x < ARENA.w / 2 + HEX_R &&
                    y > -ARENA.h / 2 - HEX_R && y < ARENA.h / 2 + HEX_R) {
                  const id = q + "," + r;
                  const cell = { id, q, r, x, y, walls: [true, true, true, true, true, true], visited: false };
                  cells.set(id, cell);
                  grid.push(cell);
                }
              }
            }

            const stack = [];
            let current = grid[Math.floor(Math.random() * grid.length)];
            current.visited = true;
            stack.push(current);

            const dirs = [
              { q: 1, r: 0 }, { q: 1, r: -1 }, { q: 0, r: -1 },
              { q: -1, r: 0 }, { q: -1, r: 1 }, { q: 0, r: 1 }
            ];

            while (stack.length > 0) {
              let neighbors = [];
              for (let i = 0; i < 6; i++) {
                const d = dirs[i];
                const nId = (current.q + d.q) + "," + (current.r + d.r);
                const n = cells.get(nId);
                if (n && !n.visited) neighbors.push({ cell: n, dir: i });
              }

              if (neighbors.length > 0) {
                const next = neighbors[Math.floor(Math.random() * neighbors.length)];
                current.walls[next.dir] = false;
                next.cell.walls[(next.dir + 3) % 6] = false;
                next.cell.visited = true;
                stack.push(next.cell);
                current = next.cell;
              } else {
                current = stack.pop();
              }
            }

            for (const c of grid) {
              cellCenters.push({ x: c.x + ARENA.w / 2, y: c.y + ARENA.h / 2 });
            }

            // Optimization: Add extra connectivity to prevent bots getting stuck in dead ends
            for (let i = 0; i < grid.length * 0.2; i++) {
              const c = grid[Math.floor(Math.random() * grid.length)];
              const wi = Math.floor(Math.random() * 6);
              c.walls[wi] = false;
            }

            // Rebuild walls array with extra openings
            for (const c of grid) {
              for (let i = 0; i < 6; i++) {
                if (c.walls[i]) {
                  const a1 = (Math.PI / 3) * i - Math.PI / 6;
                  const a2 = (Math.PI / 3) * (i + 1) - Math.PI / 6;
                  const x1 = c.x + Math.cos(a1) * HEX_R;
                  const y1 = c.y + Math.sin(a1) * HEX_R;
                  const x2 = c.x + Math.cos(a2) * HEX_R;
                  const y2 = c.y + Math.sin(a2) * HEX_R;
                  walls.push({ x1: x1 + ARENA.w / 2, y1: y1 + ARENA.h / 2, x2: x2 + ARENA.w / 2, y2: y2 + ARENA.h / 2 });
                }
              }
            }
          }

          function createPlayers() {
            players = [];
            humanPlayers = [null, null, null, null];
            for(let i=0; i<4; i++) {
              const hud = document.getElementById('hud-'+i);
              if(hud) hud.classList.remove('active');
            }

            let pId = 0;

            // Spawn Hostile Bots dynamically based on level (Level 1 = 60, Level 2 = 70, etc.)
            let enemyCount = 60 + (level - 1) * 10;
            for (let i = 0; i < enemyCount; i++) {
              players.push(createBot(pId++, 0));
            }

            // Spawn P1 (Green Team - 1 Human + 9 AI)
            spawnHumanTeam(1, 0); 
            for (let i = 0; i < 9; i++) players.push(createBot(pId++, 1));

            // Check for already connected gamepads for P2, P3, P4
            const pads = navigator.getGamepads ? navigator.getGamepads() : [];
            for(let i=1; i<4; i++) {
              if (pads[i]) {
                spawnHumanTeam(i+1, i);
                for (let j = 0; j < 9; j++) players.push(createBot(pId++, i+1));
              }
            }
          }

          function createBot(id, team) {
            let px, py, safe = false, attempts = 0;
            while (!safe && attempts < 50) {
              px = rand(100, ARENA.w - 100);
              py = rand(100, ARENA.h - 100);
              safe = true;
              for (const w of walls) {
                if (distToSegment({x: px, y: py}, w) < PLAYER_R * 3) {
                  safe = false; break;
                }
              }
              attempts++;
            }
            return {
              id: id,
              x: px, y: py,
              team: team, alive: true, health: 100, humanId: null,
              moveX: 0, moveY: 0, aimX: px+1, aimY: py, firing: false,
              angle: rand(0, Math.PI * 2),
              fireTimer: rand(800, 3500),
              moveTimer: rand(600, 2200),
              moveDir: rand(0, Math.PI * 2),
              moving: Math.random() > 0.35,
              hitFlash: 0,
              powerShots: 0,
              kills: 0,
              target: null,
              shieldTimer: 0,
              targetingVisible: false,
              lastWallHit: 0,
              stuckTimer: 0,
              lastX: px,
              lastY: py
            };
          }

          function spawnHumanTeam(team, humanId) {
            let px, py, safe = false, attempts = 0;
            while (!safe && attempts < 50) {
              px = rand(100, ARENA.w - 100);
              py = rand(100, ARENA.h - 100);
              safe = true;
              for (const w of walls) {
                if (distToSegment({x: px, y: py}, w) < PLAYER_R * 3) {
                  safe = false; break;
                }
              }
              attempts++;
            }
            const p = {
              id: players.length,
              x: px, y: py,
              team: team, alive: true, health: 100, humanId: humanId,
              moveX: 0, moveY: 0, aimX: px+1, aimY: py, firing: false,
              angle: 0,
              fireTimer: 0,
              moveTimer: 0, moveDir: 0, moving: false,
              hitFlash: 0,
              powerShots: 20, // Start with 20 yellow crystal shots
              kills: 0,
              target: null,
              shieldTimer: 30000, // Start with 30 sec shield
              targetingVisible: true, // Visible by default
              lastWallHit: 0,
              stuckTimer: 0,
              lastX: px,
              lastY: py
            };
            players.push(p);
            humanPlayers[humanId] = p;

            // Activate HUD
            const hud = document.getElementById('hud-'+humanId);
            if(hud) hud.classList.add('active');
          }

          // === GAMEPAD EVENTS ===
          window.addEventListener('gamepadconnected', (e) => {
            const index = e.gamepad.index;
            if (index < 4 && !humanPlayers[index]) {
              if (index === 0 && humanPlayers[0]) return; 

              const team = index + 1;
              spawnHumanTeam(team, index);
              for (let j = 0; j < 9; j++) players.push(createBot(players.length, team));

              if (e.gamepad.vibrationActuator) {
                e.gamepad.vibrationActuator.playEffect("dual-rumble", {
                    duration: 500,
                    strongMagnitude: 1.0,
                    weakMagnitude: 1.0
                });
              }
            }
          });

          window.addEventListener('gamepaddisconnected', (e) => {
            const index = e.gamepad.index;
            if (index < 4 && humanPlayers[index]) {
              humanPlayers[index].humanId = null;
              humanPlayers[index].moveTimer = 0;
              humanPlayers[index].fireTimer = rand(800, 3500);
              humanPlayers[index] = null;

              const hud = document.getElementById('hud-'+index);
              if(hud) hud.classList.remove('active');
            }
          });

          // === INPUT PROCESSING ===
          function processInput(dt) {
            // PC Toggle Targeting (F key)
            if (keys['f']) {
              if (!keys['_f_pressed']) {
                if (humanPlayers[0]) humanPlayers[0].targetingVisible = !humanPlayers[0].targetingVisible;
                keys['_f_pressed'] = true;
              }
            } else { keys['_f_pressed'] = false; }

            if (humanPlayers[0] && humanPlayers[0].alive) {
              const p = humanPlayers[0];
              p.moveX = 0; p.moveY = 0;
              if (keys['w']) p.moveY = -1;
              if (keys['s']) p.moveY = 1;
              if (keys['a']) p.moveX = -1;
              if (keys['d']) p.moveX = 1;

              // Aim logic: If moving with D-pad/Keys and not touching screen to aim, aim in movement direction
              if (keys['w'] || keys['a'] || keys['s'] || keys['d']) {
                if (!keys['_touch_aim']) {
                  p.aimX = p.x + p.moveX * 1000;
                  p.aimY = p.y + p.moveY * 1000;
                }
              } else if (!keys['_touch_aim']) {
                // PC Mouse aim fallback
                p.aimX = mouse.worldX;
                p.aimY = mouse.worldY;
              }

              // Shooting mechanic: triggered strictly by Q, PC Mouse, or Mobile FIRE button
              // The D-Pad does NOT set keys['mouse'], ensuring tactical movement without shooting
              p.firing = keys['q'] || keys['mouse'];
            }

            const pads = navigator.getGamepads ? navigator.getGamepads() : [];
            for (let i = 0; i < 4; i++) {
              const pad = pads[i];
              if (!pad || !humanPlayers[i] || !humanPlayers[i].alive) continue;

              const p = humanPlayers[i];

              // Xbox Toggle Targeting (Y button - index 3)
              if (pad.buttons[3] && pad.buttons[3].pressed) {
                if (!keys['_y_pressed_'+i]) {
                  p.targetingVisible = !p.targetingVisible;
                  keys['_y_pressed_'+i] = true;
                }
              } else { keys['_y_pressed_'+i] = false; }

              const dz = 0.2;
              const lx = pad.axes[0] || 0;
              const ly = pad.axes[1] || 0;

              p.moveX = lx;
              p.moveY = ly;

              if (pad.buttons[12] && pad.buttons[12].pressed) p.moveY = -1;
              if (pad.buttons[13] && pad.buttons[13].pressed) p.moveY = 1;
              if (pad.buttons[14] && pad.buttons[14].pressed) p.moveX = -1;
              if (pad.buttons[15] && pad.buttons[15].pressed) p.moveX = 1;

              const rx = pad.axes[2] || 0;
              const ry = pad.axes[3] || 0;
              if (Math.abs(rx) > dz || Math.abs(ry) > dz) {
                p.aimX = p.x + rx * 1000;
                p.aimY = p.y + ry * 1000;
              } else {
                p.aimX = p.x + Math.cos(p.angle) * 1000;
                p.aimY = p.y + Math.sin(p.angle) * 1000;
              }

              p.firing = (pad.buttons[7] && pad.buttons[7].value > 0.1) || 
                          (pad.buttons[5] && pad.buttons[5].pressed) || 
                          (pad.buttons[0] && pad.buttons[0].pressed);
            }

            for (const p of humanPlayers) {
              if (!p || !p.alive) continue;

              if (p.shieldTimer > 0) p.shieldTimer -= dt;

              if (p.moveX !== 0 || p.moveY !== 0) {
                const len = Math.hypot(p.moveX, p.moveY);
                if (len > 1) { 
                  p.moveX /= len;
                  p.moveY /= len;
                }
                p.x += p.moveX * PLAYER_SPEED;
                p.y += p.moveY * PLAYER_SPEED;
              }

              for (const w of walls) resolveCircleSegment(p, w);

              p.x = Math.max(PLAYER_R, Math.min(ARENA.w - PLAYER_R, p.x));
              p.y = Math.max(PLAYER_R, Math.min(ARENA.h - PLAYER_R, p.y));

              p.angle = Math.atan2(p.aimY - p.y, p.aimX - p.x);

              p.fireTimer -= dt;
              if (p.firing && p.fireTimer <= 0) {
                let bColor = TEAM_COLORS[p.team];
                let bType = 'normal';
                let bSize = BULLET_R;
                if (p.powerShots > 0) {
                  bColor = '#ffdd00';
                  bType = 'hex';
                  bSize = BULLET_R * 1.8;
                  p.powerShots--;
                  sfx.hexShoot();
                  if (p.powerShots === 0) sfx.empty();
                } else {
                  sfx.shoot();
                }
                spawnBullet(p, p.angle, bColor, p.team, bType, bSize);
                p.fireTimer = FIRE_COOLDOWN;
                spawnParticles(
                  p.x + Math.cos(p.angle) * (PLAYER_R + 3),
                  p.y + Math.sin(p.angle) * (PLAYER_R + 3),
                  bColor, 5, 2
                );
                shake = Math.max(shake, 3);
              }
            }
          }

          function distToSegment(p, w) {
            const l2 = Math.pow(w.x1 - w.x2, 2) + Math.pow(w.y1 - w.y2, 2);
            if (l2 === 0) return dist(p, { x: w.x1, y: w.y1 });
            let t = ((p.x - w.x1) * (w.x2 - w.x1) + (p.y - w.y1) * (w.y2 - w.y1)) / l2;
            t = Math.max(0, Math.min(1, t));
            return dist(p, { x: w.x1 + t * (w.x2 - w.x1), y: w.y1 + t * (w.y2 - w.y1) });
          }

          // Line of Sight calculation to check if walls block targeting
          function lineIntersectsWall(x1, y1, x2, y2) {
            for (const w of walls) {
              const x3 = w.x1, y3 = w.y1, x4 = w.x2, y4 = w.y2;
              const den = (x1 - x2) * (y3 - y4) - (y1 - y2) * (x3 - x4);
              if (den === 0) continue;
              const t = ((x1 - x3) * (y3 - y4) - (y1 - y3) * (x3 - x4)) / den;
              const u = -((x1 - x2) * (y1 - y3) - (y1 - y2) * (x1 - x3)) / den;
              if (t >= 0 && t <= 1 && u >= 0 && u <= 1) return true;
            }
            return false;
          }

          function resolveCircleSegment(p, w) {
            const l2 = Math.pow(w.x1 - w.x2, 2) + Math.pow(w.y1 - w.y2, 2);
            if (l2 === 0) return;
            let t = ((p.x - w.x1) * (w.x2 - w.x1) + (p.y - w.y1) * (w.y2 - w.y1)) / l2;
            t = Math.max(0, Math.min(1, t));
            const cx = w.x1 + t * (w.x2 - w.x1);
            const cy = w.y1 + t * (w.y2 - w.y1);
            const dx = p.x - cx;
            const dy = p.y - cy;
            const d = Math.hypot(dx, dy);
            if (d < PLAYER_R && d > 0) {
              p.x += (dx / d) * (PLAYER_R - d);
              p.y += (dy / d) * (PLAYER_R - d);
            }
          }

          function spawnBullet(owner, angle, color, team, type, size) {
            type = type || 'normal';
            size = size || BULLET_R;
            bullets.push({
              x: owner.x + Math.cos(angle) * (PLAYER_R + 3),
              y: owner.y + Math.sin(angle) * (PLAYER_R + 3),
              vx: Math.cos(angle) * BULLET_SPEED,
              vy: Math.sin(angle) * BULLET_SPEED,
              color, life: 110,
              ownerId: owner.id,
              team: team,
              type,
              size
            });
          }

          function spawnParticles(x, y, color, count, speed) {
            count = count || 12; speed = speed || 4;
            for (let i = 0; i < count; i++) {
              const a = rand(0, Math.PI * 2);
              const s = rand(0.5, speed);
              particles.push({
                x, y,
                vx: Math.cos(a) * s,
                vy: Math.sin(a) * s,
                life: rand(20, 45),
                maxLife: 45,
                color,
                size: rand(1, 2.6),
              });
            }
          }

          function spawnStarPowerup(x, y, isBonus) {
            if (x === undefined) {
              let px, py, safe = false, attempts = 0;
              while (!safe && attempts < 30) {
                px = rand(100, ARENA.w - 100);
                py = rand(100, ARENA.h - 100);
                safe = true;
                for (const w of walls) {
                  if (distToSegment({x: px, y: py}, w) < 40) {
                    safe = false; break;
                  }
                }
                attempts++;
              }
              x = px; y = py;
            }
            powerups.push({
              x: x, y: y,
              vx: rand(-0.8, 0.8),
              vy: rand(-0.8, 0.8),
              timer: isBonus ? 7000 : 40000,
              rot: 0,
              type: 'star',
              isBonus: isBonus || false
            });
          }

          function spawnAllyPowerup() {
            if (cellCenters.length === 0) return;
            const c = cellCenters[Math.floor(Math.random() * cellCenters.length)];
            powerups.push({
              x: c.x, y: c.y,
              vx: 0, vy: 0,
              timer: 50000,
              rot: 0,
              type: 'ally'
            });
          }

          // NEW: Shield Powerup Spawn (can spawn at center like purple or randomly)
          function spawnShieldPowerup(useCenter) {
            if (useCenter && cellCenters.length > 0) {
              const c = cellCenters[Math.floor(Math.random() * cellCenters.length)];
              powerups.push({ x: c.x, y: c.y, vx: 0, vy: 0, timer: 30000, rot: 0, type: 'shield' });
            } else {
              let px, py, safe = false, attempts = 0;
              while (!safe && attempts < 30) {
                px = rand(100, ARENA.w - 100);
                py = rand(100, ARENA.h - 100);
                safe = true;
                for (const w of walls) {
                  if (distToSegment({x: px, y: py}, w) < 40) {
                    safe = false; break;
                  }
                }
                attempts++;
              }
              powerups.push({ x: px, y: py, vx: 0, vy: 0, timer: 30000, rot: 0, type: 'shield' });
            }
          }

          function update(dt) {
            if (!running) return;

            processInput(dt);

            if (bonusActiveTimer > 0) {
              bonusActiveTimer -= dt;
            } else {
              bonusTimer -= dt;
              if (bonusTimer <= 0) {
                bonusActiveTimer = 7000;
                bonusTimer = rand(40000, 70000);
                for(let i=0; i<50; i++) {
                  spawnStarPowerup(undefined, undefined, true);
                  if (i % 5 === 0) spawnShieldPowerup(false); // Add orange crystals to bonus drift
                }
                sfx.bonus();
              }
            }

            let starCount = powerups.filter(p => p.type === 'star' && !p.isBonus).length;
            if (starCount < 3) {
              if (powerStarTimer <= 0) { spawnStarPowerup(); powerStarTimer = 500; }
              else powerStarTimer -= dt;
            } else if (starCount < 10) {
              if (powerStarTimer <= 0) { spawnStarPowerup(); powerStarTimer = rand(2000, 4000); }
              else powerStarTimer -= dt;
            }

            let allyCount = powerups.filter(p => p.type === 'ally').length;
            if (allyCount < 4) {
              if (powerAllyTimer <= 0) { spawnAllyPowerup(); powerAllyTimer = 500; }
              else powerAllyTimer -= dt;
            } else if (allyCount < 12) {
              if (powerAllyTimer <= 0) { spawnAllyPowerup(); powerAllyTimer = rand(2000, 4000); }
              else powerAllyTimer -= dt;
            }

            // NEW: Spawn at least 20 orange shield crystals
            let shieldCount = powerups.filter(p => p.type === 'shield').length;
            if (shieldCount < 20) {
              if (powerShieldTimer <= 0) { 
                spawnShieldPowerup(Math.random() > 0.5); // Mix of center and random
                powerShieldTimer = 1000; 
              } else powerShieldTimer -= dt;
            }

            for (let i = powerups.length - 1; i >= 0; i--) {
              const pu = powerups[i];
              pu.timer -= dt;
              pu.rot += 0.03;

              if (pu.type === 'star') {
                pu.x += pu.vx; pu.y += pu.vy;
                if (pu.x < 30) { pu.x = 30; pu.vx *= -1; }
                if (pu.x > ARENA.w - 30) { pu.x = ARENA.w - 30; pu.vx *= -1; }
                if (pu.y < 30) { pu.y = 30; pu.vy *= -1; }
                if (pu.y > ARENA.h - 30) { pu.y = ARENA.h - 30; pu.vy *= -1; }
              }

              if (pu.timer <= 0) {
                powerups.splice(i, 1);
                continue;
              }

              for (const p of players) {
                if (p.alive && p.team > 0 && dist(p, pu) < PLAYER_R + 14) {
                  if (pu.type === 'star') {
                    p.powerShots += 10;
                    spawnParticles(pu.x, pu.y, pu.isBonus ? '#ff3a3a' : (pu.timer <= 10000 ? '#3aafff' : '#ff3a3a'), 20, 5);
                    powerups.splice(i, 1);
                    if (p.humanId !== null) sfx.collectStar();
                  } else if (pu.type === 'ally') {
                    // Purple Crystal gives allies 5 hex shots (which enables their targeting system)
                    p.powerShots += 5;
                    players.forEach(pl => {
                      if (pl.team === p.team) pl.powerShots = 5;
                    });
                    spawnParticles(pu.x, pu.y, '#a020f0', 30, 6);
                    powerups.splice(i, 1);
                    if (p.humanId !== null) sfx.collectAlly();
                  } else if (pu.type === 'shield') {
                    // Orange Crystal gives 30 sec shield
                    p.shieldTimer = 30000;
                    spawnParticles(pu.x, pu.y, '#ff8c00', 30, 6);
                    powerups.splice(i, 1);
                    if (p.humanId !== null) sfx.collectShield();
                  }
                  break;
                }
              }
            }

            // AI Logic
            for (const p of players) {
              if (!p.alive || p.humanId !== null) continue;
              p.hitFlash = Math.max(0, p.hitFlash - dt);
              if (p.shieldTimer > 0) p.shieldTimer -= dt;

              // Targeting System: find nearest enemy WITH LINE OF SIGHT
              let target = null;
              let minTargetDist = 600; 
              for (const enemy of players) {
                if (enemy.alive && enemy.team !== p.team) {
                  const d = dist(p, enemy);
                  if (d < minTargetDist && !lineIntersectsWall(p.x, p.y, enemy.x, enemy.y)) {
                    minTargetDist = d;
                    target = enemy;
                  }
                }
              }
              p.target = target;

              p.moveTimer -= dt;
              if (p.moveTimer <= 0) {
                p.moving = Math.random() > 0.25;
                p.moveDir = rand(0, Math.PI * 2);
                p.moveTimer = rand(700, 2400);
              }

              // Unsticking mechanism
              if (p.moving) {
                p.x += Math.cos(p.moveDir) * BOT_SPEED;
                p.y += Math.sin(p.moveDir) * BOT_SPEED;
                p.angle = p.moveDir;

                p.stuckTimer -= dt;
                if (p.stuckTimer <= 0) {
                  if (Math.hypot(p.x - p.lastX, p.y - p.lastY) < 1) {
                    p.moveDir += Math.PI / 2 + rand(-0.5, 0.5); 
                    p.moveTimer = 500;
                  }
                  p.lastX = p.x;
                  p.lastY = p.y;
                  p.stuckTimer = 500;
                }
              }

              for (const w of walls) resolveCircleSegment(p, w);

              // Keep enemies strictly within the arena bounds
              if (p.x < PLAYER_R) { p.x = PLAYER_R; p.moveDir = Math.PI - p.moveDir; }
              if (p.x > ARENA.w - PLAYER_R) { p.x = ARENA.w - PLAYER_R; p.moveDir = Math.PI - p.moveDir; }
              if (p.y < PLAYER_R) { p.y = PLAYER_R; p.moveDir = -p.moveDir; }
              if (p.y > ARENA.h - PLAYER_R) { p.y = ARENA.h - PLAYER_R; p.moveDir = -p.moveDir; }

              p.fireTimer -= dt;
              if (p.fireTimer <= 0) {
                let fa = p.moving ? p.moveDir + rand(-0.4, 0.4) : rand(0, Math.PI * 2);
                let bColor = p.team > 0 ? TEAM_ALLY_COLORS[p.team] : '#ff5530';
                let bType = 'normal';
                let bSize = BULLET_R;
                let fireDelay = rand(1400, 4500);

                if (p.team > 0 && p.powerShots > 0) {
                  // Alllies use Hex Shots to break walls if blocked, OR target enemies if they have LOS
                  let nearestWall = null;
                  let minDist = Infinity;
                  for (const w of walls) {
                    const d = distToSegment(p, w);
                    if (d < minDist) {
                      minDist = d;
                      nearestWall = w;
                    }
                  }
                  if (nearestWall && minDist < 300) {
                    const mx = (nearestWall.x1 + nearestWall.x2) / 2;
                    const my = (nearestWall.y1 + nearestWall.y2) / 2;
                    fa = Math.atan2(my - p.y, mx - p.x);
                    bColor = '#ffdd00';
                    bType = 'hex';
                    bSize = BULLET_R * 1.8;
                    p.powerShots--;
                    fireDelay = rand(300, 600);
                  } else if (target) {
                    fa = Math.atan2(target.y - p.y, target.x - p.x) + rand(-0.05, 0.05);
                    bColor = '#ffdd00';
                    bType = 'hex';
                    bSize = BULLET_R * 1.8;
                    p.powerShots--;
                    fireDelay = rand(500, 1000);
                  }
                } else if (target) {
                  // Enemies and allies without power shots fire normally if they have LOS
                  fa = Math.atan2(target.y - p.y, target.x - p.x) + rand(-0.1, 0.1);
                  fireDelay = rand(800, 1800);
                }

                p.angle = fa;
                spawnBullet(p, fa, bColor, p.team, bType, bSize);
                p.fireTimer = fireDelay;
              }
            }

            // Bullets Update
            for (let i = bullets.length - 1; i >= 0; i--) {
              const b = bullets[i];
              b.x += b.vx; b.y += b.vy; b.life--;
              let hitWall = false;

              for (let j = walls.length - 1; j >= 0; j--) {
                const w = walls[j];
                if (distToSegment(b, w) < b.size) {
                  if (b.type === 'hex') {
                    walls.splice(j, 1);
                    spawnParticles(b.x, b.y, '#ffdd00', 8, 3);
                    bullets.splice(i, 1); hitWall = true;
                    const owner = players.find(pl => pl.id === b.ownerId);
                    if (owner && owner.humanId !== null) sfx.wallBreak();
                  } else {
                    spawnParticles(b.x, b.y, b.color, 4, 2);
                    bullets.splice(i, 1); hitWall = true;
                    const owner = players.find(pl => pl.id === b.ownerId);
                    if (owner && owner.humanId !== null) sfx.bounce();
                  }
                  break;
                }
              }
              if (hitWall) continue;

              if (b.life <= 0 || b.x < 0 || b.x > ARENA.w || b.y < 0 || b.y > ARENA.h) {
                bullets.splice(i, 1); continue;
              }

              for (const p of players) {
                if (!p.alive || p.id === b.ownerId) continue;
                if (p.team === b.team && p.team !== 0) continue;
                if (dist(b, p) < PLAYER_R + b.size) {
                  // Shield blocks damage
                  if (p.shieldTimer > 0) {
                    spawnParticles(p.x, p.y, '#ff8c00', 6, 3);
                    bullets.splice(i, 1);
                    break;
                  }

                  p.health -= 25;
                  p.hitFlash = 120;
                  spawnParticles(p.x, p.y, b.color, 6, 3);
                  bullets.splice(i, 1);
                  const owner = players.find(pl => pl.id === b.ownerId);
                  if (p.health <= 0) {
                    p.alive = false;
                    spawnParticles(p.x, p.y, TEAM_COLORS[p.team], 22, 5);
                    if (owner) {
                      owner.kills = (owner.kills || 0) + 1;
                      if (owner.humanId !== null) {
                        shake = 6;
                      }
                    }
                    if (p.humanId !== null) {
                      shake = 18;
                      setTimeout(endGame, 600);
                    }
                    if (owner && owner.humanId !== null) sfx.explode();
                    else if (p.humanId !== null) sfx.explode();
                    else if (Math.random() > 0.7) sfx.explode();
                  } else {
                    if (p.humanId !== null || (owner && owner.humanId !== null)) sfx.hit();
                  }
                  break;
                }
              }
            }

            for (let i = particles.length - 1; i >= 0; i--) {
              const p = particles[i];
              p.x += p.vx; p.y += p.vy;
              p.vx *= 0.92; p.vy *= 0.92;
              p.life--;
              if (p.life <= 0) particles.splice(i, 1);
            }

            // Camera Dynamic Zoom to fit all humans
            let activeHumans = humanPlayers.filter(p => p && p.alive);
            if (activeHumans.length === 0) activeHumans = players.filter(p => p.alive && p.team > 0);

            if (activeHumans.length > 0) {
              let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
              for (const p of activeHumans) {
                minX = Math.min(minX, p.x);
                maxX = Math.max(maxX, p.x);
                minY = Math.min(minY, p.y);
                maxY = Math.max(maxY, p.y);
              }
              const margin = 400;
              const bw = (maxX - minX) + margin * 2;
              const bh = (maxY - minY) + margin * 2;

              const targetScale = Math.min(W / bw, H / bh, 1.2);
              const targetX = (minX + maxX) / 2;
              const targetY = (minY + maxY) / 2;

              camera.scale += (targetScale - camera.scale) * 0.05;
              camera.x += (targetX - camera.x) * 0.08;
              camera.y += (targetY - camera.y) * 0.08;
            }

            mouse.worldX = (mouse.x - W/2) / camera.scale + camera.x;
            mouse.worldY = (mouse.y - H/2) / camera.scale + camera.y;

            shake *= 0.85;

            const alive = players.filter(p => p.alive).length;
            document.getElementById('survivors').textContent = alive;

            for(let i=0; i<4; i++) {
              const p = humanPlayers[i];
              if (p) {
                document.getElementById('kills-'+i).textContent = p.kills || 0;
                document.getElementById('hex-'+i).textContent = p.powerShots || 0;
                const hp = Math.max(0, p.health);
                const fill = document.getElementById('health-'+i);
                fill.style.width = hp + '%';
                fill.classList.toggle('low', hp <= 35);
              }
            }

            // Win condition: ALL ENEMIES KILLED
            const aliveEnemies = players.filter(p => p.team === 0 && p.alive).length;
            if (aliveEnemies === 0) {
              levelComplete();
            }
          }

          function draw() {
            ctx.fillStyle = '#070a07';
            ctx.fillRect(0, 0, W, H);

            const sx = (Math.random() - 0.5) * shake;
            const sy = (Math.random() - 0.5) * shake;

            ctx.save();
            ctx.translate(W/2 + sx, H/2 + sy);
            ctx.scale(camera.scale, camera.scale);
            ctx.translate(-camera.x, -camera.y);

            ctx.strokeStyle = 'rgba(57,255,20,0.045)';
            ctx.lineWidth = 1;
            const gs = 64;
            const viewW = W / camera.scale;
            const viewH = H / camera.scale;
            const sxg = Math.floor((camera.x - viewW/2) / gs) * gs;
            const syg = Math.floor((camera.y - viewH/2) / gs) * gs;
            ctx.beginPath();
            for (let x = sxg; x < camera.x + viewW/2 + gs; x += gs) {
              ctx.moveTo(x, camera.y - viewH/2 - gs); ctx.lineTo(x, camera.y + viewH/2 + gs);
            }
            for (let y = syg; y < camera.y + viewH/2 + gs; y += gs) {
              ctx.moveTo(camera.x - viewW/2 - gs, y); ctx.lineTo(camera.x + viewW/2 + gs, y);
            }
            ctx.stroke();

            ctx.strokeStyle = '#ffdd00';
            ctx.lineWidth = 4;
            ctx.shadowColor = '#ffdd00';
            ctx.shadowBlur = 8;
            ctx.beginPath();
            for (const w of walls) {
              ctx.moveTo(w.x1, w.y1);
              ctx.lineTo(w.x2, w.y2);
            }
            ctx.stroke();
            ctx.shadowBlur = 0;

            ctx.strokeStyle = 'rgba(57,255,20,0.35)';
            ctx.lineWidth = 2;
            ctx.strokeRect(0, 0, ARENA.w, ARENA.h);

            for (const p of particles) {
              ctx.globalAlpha = p.life / p.maxLife;
              ctx.fillStyle = p.color;
              ctx.beginPath();
              ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
              ctx.fill();
            }
            ctx.globalAlpha = 1;

            for (const pu of powerups) {
              if (pu.type === 'star') {
                const isBlue = !pu.isBonus && pu.timer <= 10000;
                const col = isBlue ? '#3aafff' : '#ff3a3a';
                ctx.save();
                ctx.translate(pu.x, pu.y);
                ctx.rotate(pu.rot);
                ctx.shadowColor = col;
                ctx.shadowBlur = 15;
                ctx.fillStyle = col;
                ctx.beginPath();
                const spikes = 5;
                const outerRadius = 14;
                const innerRadius = 5;
                for (let i = 0; i < spikes * 2; i++) {
                  const r = (i % 2 === 0) ? outerRadius : innerRadius;
                  const a = (Math.PI / spikes) * i - Math.PI / 2;
                  if (i === 0) ctx.moveTo(Math.cos(a) * r, Math.sin(a) * r);
                  else ctx.lineTo(Math.cos(a) * r, Math.sin(a) * r);
                }
                ctx.closePath();
                ctx.fill();
                ctx.restore();
              } else if (pu.type === 'ally') {
                ctx.save();
                ctx.translate(pu.x, pu.y);
                ctx.rotate(pu.rot);
                ctx.shadowColor = '#a020f0';
                ctx.shadowBlur = 18;
                ctx.fillStyle = '#a020f0';
                ctx.strokeStyle = '#e0a0ff';
                ctx.lineWidth = 2;
                ctx.beginPath();
                for (let i = 0; i < 6; i++) {
                  const a = (Math.PI / 3) * i;
                  const x = Math.cos(a) * 12;
                  const y = Math.sin(a) * 12;
                  if (i === 0) ctx.moveTo(x, y);
                  else ctx.lineTo(x, y);
                }
                ctx.closePath();
                ctx.fill();
                ctx.stroke();
                ctx.restore();
              } else if (pu.type === 'shield') {
                ctx.save();
                ctx.translate(pu.x, pu.y);
                ctx.rotate(pu.rot);
                ctx.shadowColor = '#ff8c00';
                ctx.shadowBlur = 18;
                ctx.fillStyle = '#ff8c00';
                ctx.strokeStyle = '#ffdd00';
                ctx.lineWidth = 2;
                ctx.beginPath();
                for (let i = 0; i < 6; i++) {
                  const a = (Math.PI / 3) * i;
                  const x = Math.cos(a) * 13;
                  const y = Math.sin(a) * 13;
                  if (i === 0) ctx.moveTo(x, y);
                  else ctx.lineTo(x, y);
                }
                ctx.closePath();
                ctx.fill();
                ctx.stroke();
                ctx.restore();
              }
            }
            ctx.shadowBlur = 0;

            for (const b of bullets) {
              ctx.shadowColor = b.color;
              ctx.shadowBlur = 10;
              ctx.fillStyle = b.color;
              if (b.type === 'hex') {
                ctx.save();
                ctx.translate(b.x, b.y);
                ctx.rotate(Math.atan2(b.vy, b.vx));
                ctx.beginPath();
                for (let i = 0; i < 6; i++) {
                  const a = (Math.PI / 3) * i;
                  const x = Math.cos(a) * b.size;
                  const y = Math.sin(a) * b.size;
                  if (i === 0) ctx.moveTo(x, y);
                  else ctx.lineTo(x, y);
                }
                ctx.closePath();
                ctx.fill();
                ctx.restore();
              } else {
                ctx.beginPath();
                ctx.arc(b.x, b.y, b.size, 0, Math.PI * 2);
                ctx.fill();
                ctx.globalAlpha = 0.35;
                ctx.beginPath();
                ctx.arc(b.x - b.vx * 1.5, b.y - b.vy * 1.5, b.size * 0.7, 0, Math.PI * 2);
                ctx.fill();
                ctx.globalAlpha = 1;
              }
            }
            ctx.shadowBlur = 0;

            // Draw Targeting Lasers & Crosshairs
            for (const p of players) {
              if (!p.alive) continue;
              if (p.humanId !== null && p.targetingVisible) {
                // Enhanced Targeting System: Crosshair with Circle
                ctx.strokeStyle = 'rgba(255,255,255,0.8)';
                ctx.lineWidth = 1.5;
                ctx.beginPath();
                const cs = 12;
                const r = 16; // Radius of the circle
                // Draw Circle
                ctx.arc(p.aimX, p.aimY, r, 0, Math.PI * 2);
                // Draw Cross lines outside the circle
                ctx.moveTo(p.aimX - cs - r, p.aimY); ctx.lineTo(p.aimX - r - 2, p.aimY);
                ctx.moveTo(p.aimX + r + 2, p.aimY); ctx.lineTo(p.aimX + cs + r, p.aimY);
                ctx.moveTo(p.aimX, p.aimY - cs - r); ctx.lineTo(p.aimX, p.aimY - r - 2);
                ctx.moveTo(p.aimX, p.aimY + r + 2); ctx.lineTo(p.aimX, p.aimY + cs + r);
                ctx.stroke();

                // Inner dot
                ctx.fillStyle = TEAM_COLORS[p.team];
                ctx.beginPath();
                ctx.arc(p.aimX, p.aimY, 2, 0, Math.PI * 2);
                ctx.fill();
              } else if (p.target) {
                // Faint laser sight for AI that have a valid line of sight target
                ctx.strokeStyle = p.team === 0 ? 'rgba(255, 50, 50, 0.2)' : 'rgba(57, 255, 20, 0.2)';
                ctx.lineWidth = 1;
                ctx.setLineDash([3, 6]);
                ctx.beginPath();
                ctx.moveTo(p.x, p.y);
                ctx.lineTo(p.target.x, p.target.y);
                ctx.stroke();
                ctx.setLineDash([]);
              }
            }

            for (const p of players) {
              if (!p.alive) continue;
              ctx.save();
              ctx.translate(p.x, p.y);
              ctx.rotate(p.angle);

              // MODIFIED: Enemies (team 0) are white with a yellow glow
              const body = p.team === 0 ? '#ffffff' : TEAM_COLORS[p.team];
              const stroke = p.humanId !== null ? '#ffffff' : (p.team > 0 ? TEAM_COLORS[p.team] : '#ffdd00');
              const flash = p.hitFlash > 0 ? '#ffffff' : body;

              if (p.humanId !== null) {
                ctx.shadowColor = TEAM_COLORS[p.team];
                ctx.shadowBlur = 22;
                ctx.strokeStyle = TEAM_COLORS[p.team];
                ctx.lineWidth = 2;
              } else if (p.team === 0) {
                ctx.shadowColor = '#ffdd00';
                ctx.shadowBlur = 15;
                ctx.strokeStyle = '#ffdd00';
                ctx.lineWidth = 1.5;
              } else {
                ctx.strokeStyle = stroke;
                ctx.lineWidth = 1;
              }

              ctx.beginPath();
              ctx.moveTo(PLAYER_R, 0);
              ctx.lineTo(-PLAYER_R * 0.7, -PLAYER_R * 0.7);
              ctx.lineTo(-PLAYER_R * 0.7, PLAYER_R * 0.7);
              ctx.closePath();
              ctx.fillStyle = flash;
              ctx.fill();
              ctx.stroke();

              if (p.powerShots > 0) {
                  ctx.fillStyle = '#ffdd00';
                  ctx.beginPath();
                  ctx.arc(0, 0, 3, 0, Math.PI * 2);
                  ctx.fill();
              }

              ctx.restore();

              // Shield rendering logic
              if (p.shieldTimer > 0) {
                const pulse = Math.sin(Date.now() / 100) * 3;
                ctx.save();
                ctx.translate(p.x, p.y);

                // Outer glow
                ctx.shadowColor = '#ff8c00';
                ctx.shadowBlur = 25;
                ctx.strokeStyle = '#ff8c00';
                ctx.lineWidth = 4;
                ctx.beginPath();
                ctx.arc(0, 0, PLAYER_R + 10 + pulse, 0, Math.PI * 2);
                ctx.stroke();

                // Inner glow
                ctx.shadowBlur = 15;
                ctx.strokeStyle = '#ffdd00';
                ctx.lineWidth = 2;
                ctx.beginPath();
                ctx.arc(0, 0, PLAYER_R + 6 + pulse, 0, Math.PI * 2);
                ctx.stroke();

                ctx.restore();
              }

              if (p.humanId !== null) {
                ctx.fillStyle = 'rgba(255,255,255,0.8)';
                ctx.font = 'bold 10px JetBrains Mono';
                ctx.textAlign = 'center';
                ctx.fillText('P' + (p.humanId + 1), p.x, p.y - 18);
              }
            }

            ctx.restore();
          }

          function levelComplete() {
            running = false;
            level++;
            const overlay = document.getElementById('overlay');
            overlay.innerHTML = `
              <h1><span class="green">SECTOR</span><br/>CLEARED</h1>
              <p>PROTOCOL LEVEL ${level} INITIATED<br/>SURVIVORS: ${players.filter(p => p.alive).length}</p>
              <button id="start">CONTINUE</button>
            `;
            overlay.classList.add('active');
            document.getElementById('start').addEventListener('click', startGame);
            sfx.levelUp();
          }

          function endGame() {
            if (gameOver) return;
            gameOver = true;
            running = false;
            level = 1; // Reset level to 1 on game over
            sfx.gameOver();
            const overlay = document.getElementById('overlay');
            let totalKills = 0;
            humanPlayers.forEach(p => { if(p) totalKills += (p.kills || 0); });
            overlay.innerHTML = `
              <h1><span class="red">SYSTEM</span><br/>FAILURE</h1>
              <div class="stats">
                <div class="stat">
                  <div class="num">${totalKills}</div>
                  <div class="lbl">TOTAL KILLS</div>
                </div>
                <div class="stat">
                  <div class="num">${level}</div>
                  <div class="lbl">SECTORS</div>
                </div>
              </div>
              <button id="start">RESTART</button>
            `;
            overlay.classList.add('active');
            document.getElementById('start').addEventListener('click', startGame);
          }

          function startGame() {
            initAudio();
            gameOver = false;
            running = true;
            generateMaze();
            createPlayers();
            camera.scale = 1.0;
            camera.x = ARENA.w / 2;
            camera.y = ARENA.h / 2;
            powerShieldTimer = 30000;
            // Initial spawn of 20 orange crystals
            for(let i=0; i<20; i++) {
              spawnShieldPowerup(Math.random() > 0.5);
            }
            const overlay = document.getElementById('overlay');
            overlay.classList.remove('active');
          }

          function gameLoop(timestamp) {
            const dt = 16; 
            update(dt);
            draw();
            requestAnimationFrame(gameLoop);
          }

          document.getElementById('start').addEventListener('click', startGame);

          window.addEventListener('keydown', e => { keys[e.key.toLowerCase()] = true; });
          window.addEventListener('keyup', e => { keys[e.key.toLowerCase()] = false; });

          canvas.addEventListener('mousemove', e => {
            const rect = canvas.getBoundingClientRect();
            mouse.x = e.clientX - rect.left;
            mouse.y = e.clientY - rect.top;
          });
          canvas.addEventListener('mousedown', e => { keys['mouse'] = true; });
          canvas.addEventListener('mouseup', e => { keys['mouse'] = false; });

          window.addEventListener('contextmenu', e => e.preventDefault());

          // --- ANDROID / MOBILE TACTICAL D-PAD FIX ---
          // e.stopPropagation() prevents the canvas from receiving the touch and triggering firing.
          const touchControls = {
            up: document.getElementById('btn-up'),
            down: document.getElementById('btn-down'),
            left: document.getElementById('btn-left'),
            right: document.getElementById('btn-right')
          };
          for (const dir in touchControls) {
            const btn = touchControls[dir];
            if (!btn) continue;
            const key = dir === 'up' ? 'w' : dir === 'down' ? 's' : dir === 'left' ? 'a' : 'd';
            btn.addEventListener('touchstart', e => { 
                e.preventDefault(); 
                e.stopPropagation(); 
                keys[key] = true; 
                // D-pad strictly handles movement, NO FIRING INITIALIZED HERE
            }, {passive: false});
            btn.addEventListener('touchend', e => { 
                e.preventDefault(); 
                e.stopPropagation(); 
                keys[key] = false; 
            }, {passive: false});
            btn.addEventListener('touchcancel', e => { 
                e.preventDefault(); 
                e.stopPropagation(); 
                keys[key] = false; 
            }, {passive: false});
          }

          // Dedicated FIRE Button
          const fireBtn = document.getElementById('btn-fire');
          if (fireBtn) {
              fireBtn.addEventListener('touchstart', e => { 
                  e.preventDefault(); 
                  e.stopPropagation(); 
                  keys['mouse'] = true; // Fire button handles shooting
              }, {passive: false});
              fireBtn.addEventListener('touchend', e => { 
                  e.preventDefault(); 
                  e.stopPropagation(); 
                  keys['mouse'] = false; 
              }, {passive: false});
              fireBtn.addEventListener('touchcancel', e => { 
                  e.preventDefault(); 
                  e.stopPropagation(); 
                  keys['mouse'] = false; 
              }, {passive: false});
          }

          // Touching the main screen to aim ONLY. No shooting from screen drag.
          canvas.addEventListener('touchstart', e => {
              e.preventDefault();
              const rect = canvas.getBoundingClientRect();
              mouse.x = e.touches[0].clientX - rect.left;
              mouse.y = e.touches[0].clientY - rect.top;
              keys['_touch_aim'] = true; // Mark that we are aiming via touch
              // NO keys['mouse'] = true. Screen touch does not fire.
          }, {passive: false});

          canvas.addEventListener('touchmove', e => {
              e.preventDefault();
              const rect = canvas.getBoundingClientRect();
              mouse.x = e.touches[0].clientX - rect.left;
              mouse.y = e.touches[0].clientY - rect.top;
          }, {passive: false});

          canvas.addEventListener('touchend', e => {
              e.preventDefault();
              keys['_touch_aim'] = false;
          }, {passive: false});

          canvas.addEventListener('touchcancel', e => {
              e.preventDefault();
              keys['_touch_aim'] = false;
          }, {passive: false});

          requestAnimationFrame(gameLoop);

